namespace sv_dac6eb8ce9c54fb8be9081787ad96a8a.Models;

// Service contracts
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for two-way binding
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public PersonalInfo ToRecord() => new(FullName, Email, Phone, Address);
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public WorkEntry ToRecord() => new(Company, Title, StartDate ?? DateTime.Today, IsCurrent ? null : EndDate, Description);
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public Reference ToRecord() => new(Name, Relationship, Email, Phone);
}

@namespace sv_dac6eb8ce9c54fb8be9081787ad96a8a.Components.Pages.Apply

<nav class="step-indicator mb-4" aria-label="Application steps">
    <ol class="d-flex list-unstyled justify-content-between p-0 m-0">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var isCurrent = stepIndex == CurrentStep;
            var isCompleted = stepIndex < CurrentStep;
            var isFuture = stepIndex > CurrentStep;

            <li class="step-item flex-fill text-center @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "dimmed" : "")">
                @if (isCompleted)
                {
                    <button type="button" class="btn btn-link step-btn p-0 text-decoration-none" @onclick="() => OnStepClicked.InvokeAsync(stepIndex)">
                        <span class="step-circle bg-success text-white">✓</span>
                        <span class="step-label d-block mt-1 text-success fw-semibold">@StepNames[stepIndex]</span>
                    </button>
                }
                else
                {
                    <div>
                        <span class="step-circle @(isCurrent ? "bg-primary text-white" : "bg-secondary text-white")">@(stepIndex + 1)</span>
                        <span class="step-label d-block mt-1 @(isCurrent ? "fw-semibold text-primary" : "text-muted")">@StepNames[stepIndex]</span>
                    </div>
                }
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public IReadOnlyList<string> StepNames { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

.step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 2rem;
    height: 2rem;
    border-radius: 50%;
    font-size: 0.85rem;
    font-weight: 600;
}

.step-item.dimmed {
    opacity: 0.5;
}

.step-btn {
    border: none;
    background: none;
    cursor: pointer;
}

.step-btn:hover .step-label {
    text-decoration: underline;
}

.step-label {
    font-size: 0.85rem;
}

@namespace sv_dac6eb8ce9c54fb8be9081787ad96a8a.Components.Pages.Apply
@using sv_dac6eb8ce9c54fb8be9081787ad96a8a.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Reference @(Index + 1)</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
            }
        </div>
        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Reference.Name" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Reference.Relationship" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" @bind="Reference.Email" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" @bind="Reference.Phone" />
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ReferenceModel Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

@namespace sv_dac6eb8ce9c54fb8be9081787ad96a8a.Components.Pages.Apply
@using sv_dac6eb8ce9c54fb8be9081787ad96a8a.Models

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Model.FullName" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" @bind="Model.Email" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Model.Phone" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Model.Address" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <text>Validating…</text>
        }
        else
        {
            <text>Next</text>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            ErrorMessage = "All fields are required.";
            return;
        }

        IsValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!emailValid)
            {
                ErrorMessage = "The email address is not valid. Please check and try again.";
                return;
            }
            await OnNext.InvokeAsync();
        }
        finally
        {
            IsValidating = false;
        }
    }
}

@namespace sv_dac6eb8ce9c54fb8be9081787ad96a8a.Components.Pages.Apply
@using sv_dac6eb8ce9c54fb8be9081787ad96a8a.Models

<h4 class="mb-3">Work History</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryEditor Entry="Entries[index]"
                     Index="index"
                     CanRemove="Entries.Count > 1"
                     OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-primary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between mt-3">
    <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;
        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) ||
                string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate is null)
            {
                ErrorMessage = "Company, job title, and start date are required for each position.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }
}

@namespace sv_dac6eb8ce9c54fb8be9081787ad96a8a.Components.Pages.Apply
@using sv_dac6eb8ce9c54fb8be9081787ad96a8a.Models

<h4 class="mb-3">References</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceEditor Reference="References[index]"
                     Index="index"
                     CanRemove="References.Count > 2"
                     OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-primary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between mt-3">
    <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;
        if (References.Count < 2)
        {
            ErrorMessage = "At least 2 references are required.";
            return;
        }

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) ||
                string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) ||
                string.IsNullOrWhiteSpace(r.Phone))
            {
                ErrorMessage = "All fields are required for each reference.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }
}

@namespace sv_dac6eb8ce9c54fb8be9081787ad96a8a.Components.Pages.Apply

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <textarea class="form-control" rows="12" maxlength="@MaxLength"
              @bind="CoverLetter" @bind:event="oninput"></textarea>
    <div class="form-text text-end">
        @(CoverLetter?.Length ?? 0) / @MaxLength characters
    </div>
</div>

<div class="d-flex justify-content-between mt-3">
    <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="OnNext">Next</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
}

@namespace sv_dac6eb8ce9c54fb8be9081787ad96a8a.Components.Pages.Apply
@using sv_dac6eb8ce9c54fb8be9081787ad96a8a.Models

<h4 class="mb-3">Review &amp; Submit</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@if (SubmittedId.HasValue)
{
    <div class="alert alert-success">
        <h5>Application Submitted!</h5>
        <p class="mb-0">Your application ID is <strong>#@SubmittedId</strong>. Thank you for applying!</p>
    </div>
}
else
{
    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick='() => OnEditSection.InvokeAsync(0)'>Edit</button>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@Personal.FullName</dd>
                <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Personal.Email</dd>
                <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Personal.Phone</dd>
                <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Personal.Address</dd>
            </dl>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick='() => OnEditSection.InvokeAsync(1)'>Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3">
                    <h6>@entry.Title at @entry.Company</h6>
                    <p class="text-muted mb-1">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </p>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick='() => OnEditSection.InvokeAsync(2)'>Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> — @r.Relationship<br />
                    <span class="text-muted">@r.Email · @r.Phone</span>
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick='() => OnEditSection.InvokeAsync(3)'>Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button type="button" class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <text>Submitting…</text>
            }
            else
            {
                <text>Submit Application</text>
            }
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private bool IsSubmitting;
    private int? SubmittedId;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        IsSubmitting = true;
        ErrorMessage = null;
        try
        {
            var application = new JobApplication(
                Personal.ToRecord(),
                new WorkHistory(WorkEntries.Select(e => e.ToRecord()).ToList()),
                References.Select(r => r.ToRecord()).ToList(),
                CoverLetter);

            SubmittedId = await ApplicationService.SubmitApplicationAsync(application);
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

namespace sv_dac6eb8ce9c54fb8be9081787ad96a8a.Models;

// Service contracts
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for two-way binding
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
