@page "/apply"
@rendermode InteractiveServer
@using sv_dac6eb8ce9c54fb8be9081787ad96a8a.Models
@using sv_dac6eb8ce9c54fb8be9081787ad96a8a.Components.Pages.Apply
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="_currentStep"
                   StepNames="_stepNames"
                   OnStepClicked="GoToStep" />

    @switch (_currentStep)
    {
        case 0:
            <PersonalInfoStep Model="_personal"
                              ApplicationService="ApplicationService"
                              OnNext="NextStep" />
            break;

        case 1:
            <WorkHistoryStep Entries="_workEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 2:
            <ReferencesStep References="_references"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;

        case 3:
            <CoverLetterStep @bind-CoverLetter="_coverLetter"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 4:
            <ReviewStep Personal="_personal"
                        WorkEntries="_workEntries"
                        References="_references"
                        CoverLetter="_coverLetter"
                        ApplicationService="ApplicationService"
                        OnEditSection="GoToStep"
                        OnBack="PreviousStep" />
            break;
    }
</div>

@code {
    private static readonly IReadOnlyList<string> _stepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private int _currentStep;

    // Form state
    private readonly PersonalInfoModel _personal = new();
    private readonly List<WorkEntryModel> _workEntries = [new()];
    private readonly List<ReferenceModel> _references = [new(), new()];
    private string _coverLetter = "";

    private void NextStep() => _currentStep = Math.Min(_currentStep + 1, _stepNames.Count - 1);
    private void PreviousStep() => _currentStep = Math.Max(_currentStep - 1, 0);
    private void GoToStep(int step)
    {
        if (step < _currentStep)
            _currentStep = step;
    }
}

